<script setup lang="ts">
  import { ref, computed } from 'vue';
  import { useData } from 'vitepress';
  import { gridExamples } from '../grid-examples';
  // @ts-ignore — virtual module generated by Vite plugin at build time
  import { highlightedExamples } from 'virtual:highlighted-examples';

  const props = defineProps<{
    name?: string;
    code?: string;
    examples?: Record<string, string>;
  }>();

  const { isDark } = useData();

  const resolvedCode = computed(() => {
    if (props.code) return props.code;
    const source = props.examples ?? gridExamples;
    if (props.name && props.name in source) return source[props.name];
    return '';
  });

  const highlightedHtml = computed(() => {
    if (props.name && props.name in highlightedExamples) {
      const entry = highlightedExamples[props.name];
      return isDark.value ? entry.dark : entry.light;
    }
    return '';
  });

  // Copy to clipboard
  const copied = ref(false);

  async function copyCode() {
    try {
      await navigator.clipboard.writeText(resolvedCode.value);
      copied.value = true;
      setTimeout(() => (copied.value = false), 2000);
    } catch {
      // Clipboard API unavailable
    }
  }

  const activeTab = ref<'code' | 'preview'>('preview');
</script>

<template>
  <div class="code-preview">
    <div class="code-preview__tabs">
      <button
        :class="['code-preview__tab', { active: activeTab === 'code' }]"
        @click="activeTab = 'code'"
      >
        Code
      </button>
      <button
        :class="['code-preview__tab', { active: activeTab === 'preview' }]"
        @click="activeTab = 'preview'"
      >
        Preview
      </button>
      <button
        v-if="activeTab === 'code'"
        class="code-preview__copy"
        @click="copyCode"
      >
        {{ copied ? 'Copied!' : 'Copy' }}
      </button>
    </div>

    <div v-show="activeTab === 'code'" class="code-preview__code">
      <div v-if="highlightedHtml" v-html="highlightedHtml" />
      <pre v-else><code>{{ resolvedCode }}</code></pre>
    </div>

    <div v-show="activeTab === 'preview'" class="code-preview__preview">
      <div v-html="resolvedCode" class="code-preview__result"></div>
    </div>
  </div>
</template>

<style scoped>
