    color: var(--vp-c-text-1);
  }

  .code-preview__tab.active {
    color: var(--vp-c-brand-1);
    border-bottom-color: var(--vp-c-brand-1);
  }

  .code-preview__copy {
    margin-left: auto;
    margin-right: 0.5rem;
    padding: 0.25rem 0.75rem;
    font-size: 0.75rem;
    background: none;
    border: 1px solid var(--vp-c-divider);
    border-radius: 4px;
    color: var(--vp-c-text-2);
    cursor: pointer;
  }

  .code-preview__copy:hover {
    color: var(--vp-c-text-1);
    border-color: var(--vp-c-text-3);
  }

  .code-preview__code,
  .code-preview__preview {
    padding: 1rem;
    min-height: 80px;
  }

  .code-preview__code {
    background: var(--vp-code-block-bg);
    overflow-x: auto;
  }

  /* Fallback (plain text, used for inline code prop without pre-highlighting) */
  .code-preview__code pre {
    margin: 0;
    font-size: 0.8125rem;
    line-height: 1.5;
  }

  .code-preview__code code {
    font-family: var(--vp-font-family-mono);
    color: var(--vp-c-text-1);
  }

  /* Shiki output */
  .code-preview__code :deep(pre.shiki) {
    margin: 0;
    padding: 0;
    background: transparent !important;
    font-size: 0.8125rem;
    line-height: 1.5;
  }

  .code-preview__code :deep(pre.shiki code) {
    font-family: var(--vp-font-family-mono);
  }

  .code-preview__preview {
    background: var(--vp-c-bg-soft);
  }

  .code-preview__result {
    font-size: 0.875rem;
  }

  /* Generic: style children of any grid container in preview */
  .code-preview__result :deep([class*='grid']) > * {
    padding: 0.5rem 0.75rem;
    background: var(--vp-c-bg-soft);
    border: 1px dashed var(--vp-c-divider);
    border-radius: 4px;
  }

  /* Card children: slightly larger padding and radius */
  .code-preview__result :deep(.grid-cards) .card {
    padding: 0.75rem 1rem;
    border-radius: 6px;
  }

  /* Holy grail needs min-height to show the layout */
  .code-preview__result :deep(.grid-holy-grail) {
    min-height: 180px;
  }
</style>
